{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://xananode.org/schemas/xananode-relationship-types.schema.v0.4.0.json",
  "title": "XanaNode Relationship Type Registry",
  "description": "Canonical and extension relationship type registry for XanaNode-compatible knowledge substrates.",
  "type": "object",
  "additionalProperties": false,
  "required": [
    "version",
    "relationship_types"
  ],
  "properties": {
    "version": {
      "type": "string"
    },
    "namespace": {
      "type": "string",
      "pattern": "^[a-z][a-z0-9_-]*(\\.[a-z][a-z0-9_-]*)*$"
    },
    "relationship_types": {
      "type": "array",
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": [
          "namespace",
          "id",
          "type",
          "label",
          "category",
          "meaning",
          "default_weight",
          "default_visibility"
        ],
        "properties": {
          "namespace": {
            "type": "string",
            "pattern": "^[a-z][a-z0-9_-]*(\\.[a-z][a-z0-9_-]*)*$"
          },
          "id": {
            "type": "string",
            "pattern": "^[a-z][a-z0-9_-]*(\\.[a-z][a-z0-9_-]*)*:[a-z][a-z0-9_-]*$"
          },
          "type": {
            "type": "string",
            "pattern": "^[a-z][a-z0-9_-]*$"
          },
          "label": {
            "type": "string"
          },
          "category": {
            "type": "string",
            "anyOf": [
              {
                "enum": [
                  "causation",
                  "citation",
                  "claim_structure",
                  "comparison",
                  "composition",
                  "creation",
                  "definition",
                  "evidence",
                  "explanation",
                  "generic",
                  "governance",
                  "historical",
                  "identity",
                  "influence",
                  "lineage",
                  "location",
                  "participation",
                  "reasoning",
                  "representation",
                  "revision",
                  "schema_mapping",
                  "social",
                  "temporal"
                ]
              },
              {
                "pattern": "^[a-z][a-z0-9_:-]*$"
              }
            ]
          },
          "meaning": {
            "type": "string"
          },
          "inverse": {
            "type": "string"
          },
          "core": {
            "type": "boolean"
          },
          "extends": {
            "type": [
              "string",
              "null"
            ],
            "pattern": "^[a-z][a-z0-9_-]*(\\.[a-z][a-z0-9_-]*)*(:[a-z][a-z0-9_-]*)?$"
          },
          "default_weight": {
            "type": "integer",
            "minimum": 1,
            "maximum": 5
          },
          "default_visibility": {
            "type": "string",
            "enum": [
              "primary",
              "secondary",
              "background"
            ]
          }
        }
      }
    }
  }
}
